  // نفس الـ style من Landing (النجوم والشهب والخلفية المتحركة)
  const backgroundStyle = `
    @keyframes gradientShift {
      0% { background-position: 0% 50%; }
      50% { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }
    
    .hero-section {
      position: relative;
      background: linear-gradient(135deg, #0a0a2a, #1a1a3a, #0d0d2b, #0f0c29, #1a1a4a);
      background-size: 400% 400%;
      animation: gradientShift 12s ease infinite;
      min-height: 100vh;
    }
    
    /* تأثير الشهب */
    .shooting-stars {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      pointer-events: none;
      z-index: 1;
      overflow: hidden;
    }
    
    .shooting-star {
      position: absolute;
      width: 2px;
      height: 2px;
      background: linear-gradient(135deg, rgba(255,255,255,1) 0%, rgba(255,255,255,0) 100%);
      border-radius: 50%;
      opacity: 0;
      animation: shoot 2s ease-out infinite;
    }
    
    @keyframes shoot {
      0% {
        transform: translateX(0) translateY(0) rotate(45deg);
        opacity: 0;
      }
      5% {
        opacity: 1;
      }
      95% {
        opacity: 1;
      }
      100% {
        transform: translateX(-300px) translateY(300px) rotate(45deg);
        opacity: 0;
      }
    }
    
    /* نجوم صغيرة */
    .star {
      position: absolute;
      background: white;
      border-radius: 50%;
      opacity: 0.6;
      animation: twinkle 3s ease-in-out infinite;
    }
    
    @keyframes twinkle {
      0%, 100% { opacity: 0.2; transform: scale(1); }
      50% { opacity: 1; transform: scale(1.2); }
    }
    
    /* المربع الملون المتحرك */
    .morphing-bg {
      width: 100%;
      max-width: 1100px;
      min-height: 420px;
      background: linear-gradient(45deg, #ee7752, #e73c7e, #23a6d5, #23d5ad);
      background-size: 400% 400%;
      animation: gradient 8s ease infinite, morph 8s ease-in-out infinite;
      border-radius: 30px;
      transform-style: preserve-3d;
      box-shadow: 0 20px 40px rgba(0,0,0,0.3);
      border: 2px solid rgba(255,255,255,0.2);
      margin: 0 auto;
      padding: 90px 20px 30px 20px;
      position: relative;
      margin-top: 90px;
    }
    
    @keyframes gradient {
      0% { background-position: 0% 50%; }
      50% { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }
    
    @keyframes morph {
      0% { border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%; }
      50% { border-radius: 30% 60% 70% 40% / 50% 60% 30% 60%; }
      100% { border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%; }
    }
    
    .image-wrapper {
      position: absolute;
      top: -90px;
      left: 50%;
      transform: translateX(-50%);
      z-index: 20;
    }
    
    @media (max-width: 768px) {
      .morphing-bg {
        min-height: 500px;
        border-radius: 20px;
        padding: 75px 15px 25px 15px;
        margin-top: 75px;
      }
      .image-wrapper {
        top: -75px;
      }
    }
  `;

  // رابط صورة البروفايل
  const profileImageUrl = "https://scontent.ftun19-1.fna.fbcdn.net/v/t39.30808-1/570088560_1892287584661197_1770332595867547250_n.jpg?stp=dst-jpg_s200x200_tt6&_nc_cat=108&ccb=1-7&_nc_sid=1d2534&_nc_ohc=jw_gXXdbsN8Q7kNvwGsJXf8&_nc_oc=AdqlWXqggAVcN4yQpsUcCgiIGbuaTTU75NWlrLzQiNLF9zwHxxK2WWlY0bnmX1zG-xk&_nc_zt=24&_nc_ht=scontent.ftun19-1.fna&_nc_gid=f2fDNb2dVa1z2uz-9cTN0w&_nc_ss=7a3a8&oh=00_Af36ZMmNkSzPh_1wnNCzeZBpeEyZs1SUTiAYLZn4y8wLBA&oe=69D45FD6";

  return (
    <>
      <style>{backgroundStyle}</style>
      
      {/* رابط Font Awesome */}
      <link 
        rel="stylesheet" 
        href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.7.2/css/all.min.css"
        crossOrigin="anonymous" 
        referrerPolicy="no-referrer"
      />
      
      {/* نفس الهيكل بتاع Landing مع الخلفية والنجوم */}
      <div className="hero-section" style={{ position: 'relative', minHeight: '100vh' }}>
        
        {/* النجوم والشهب */}
        <div className="shooting-stars">
          {[...Array(50)].map((_, i) => (
            <div
              key={i}
              className="star"
              style={{
                left: `${Math.random() * 100}%`,
                top: `${Math.random() * 100}%`,
                width: `${Math.random() * 3 + 1}px`,
                height: `${Math.random() * 3 + 1}px`,
                animationDelay: `${Math.random() * 5}s`,
                animationDuration: `${Math.random() * 3 + 2}s`
              }}
            />
          ))}
          
          {[...Array(8)].map((_, i) => (
            <div
              key={`shooting-${i}`}
              className="shooting-star"
              style={{
                left: `${Math.random() * 80 + 10}%`,
                top: `${Math.random() * 40}%`,
                width: `${Math.random() * 60 + 40}px`,
                height: '2px',
                animationDelay: `${Math.random() * 8}s`,
                animationDuration: `${Math.random() * 2 + 1.5}s`,
                transform: `rotate(${Math.random() * 60 + 30}deg)`,
                background: `linear-gradient(90deg, 
                  rgba(255,255,255,1) 0%, 
                  rgba(255,255,150,0.8) 30%,
                  rgba(255,255,255,0) 100%)`
              }}
            />
          ))}
        </div>
        
        <main style={{ position: 'relative', zIndex: 10 }}>
          <section className="relative block h-500-px">
            <div
              className="absolute top-0 w-full h-full bg-center bg-cover"
              style={{
                backgroundImage:
                  "url('https://png.pngtree.com/thumb_back/fw800/background/20240602/pngtree-bartender-cleaning-counter-in-a-nice-pub-image_15737949.jpg')",
              }}
            >
              <span
                id="blackOverlay"
                className="w-full h-full absolute opacity-50 bg-black"
              ></span>
            </div>
            <div
              className="top-auto bottom-0 left-0 right-0 w-full absolute pointer-events-none overflow-hidden h-70-px"
              style={{ transform: "translateZ(0)" }}
            >
              <svg
                className="absolute bottom-0 overflow-hidden"
                xmlns="http://www.w3.org/2000/svg"
                preserveAspectRatio="none"
                version="1.1"
                viewBox="0 0 2560 100"
                x="0"
                y="0"
              >
                <polygon
                  className="text-blueGray-200 fill-current"
                  points="2560 0 2560 100 0 100"
                ></polygon>
              </svg>
            </div>
          </section>
          
          <section className="relative py-16 bg-blueGray-200">
            <div className="container mx-auto px-4">
              <div className="relative flex flex-col min-w-0 break-words bg-white w-full mb-6 shadow-xl rounded-lg -mt-64">
                <div className="px-6">
                  <div className="flex flex-wrap justify-center">
                    <div className="w-full lg:w-3/12 px-4 lg:order-2 flex justify-center">
                      <div className="relative">
                        <img
                          alt="..."
                          src={require("assets/img/team-2-800x800.jpg").default}
                          className="shadow-xl rounded-full h-auto align-middle border-none absolute -m-16 -ml-20 lg:-ml-16 max-w-150-px"
                        />
                      </div>
                    </div>
                    <div className="w-full lg:w-4/12 px-4 lg:order-3 lg:text-right lg:self-center">
                      <div className="py-6 px-3 mt-32 sm:mt-0">
                        <button
                          className="bg-lightBlue-500 active:bg-lightBlue-600 uppercase text-white font-bold hover:shadow-md shadow text-xs px-4 py-2 rounded outline-none focus:outline-none sm:mr-2 mb-1 ease-linear transition-all duration-150"
                          type="button"
                        >
                          Connect
                        </button>
                      </div>
                    </div>
                    <div className="w-full lg:w-4/12 px-4 lg:order-1">
                      <div className="flex justify-center py-4 lg:pt-4 pt-8">
                        <div className="mr-4 p-3 text-center">
                          <span className="text-xl font-bold block uppercase tracking-wide text-blueGray-600">
                            22
                          </span>
                          <span className="text-sm text-blueGray-400">
                            Friends
                          </span>
                        </div>
                        <div className="mr-4 p-3 text-center">
                          <span className="text-xl font-bold block uppercase tracking-wide text-blueGray-600">
                            10
                          </span>
                          <span className="text-sm text-blueGray-400">
                            Photos
                          </span>
                        </div>
                        <div className="lg:mr-4 p-3 text-center">
                          <span className="text-xl font-bold block uppercase tracking-wide text-blueGray-600">
                            89
                          </span>
                          <span className="text-sm text-blueGray-400">
                            Comments
                          </span>
                        </div>
                      </div>
                    </div>
                  </div>
                  
                  <div className="text-center mt-12">
                    <h3 className="text-4xl font-semibold leading-normal mb-2 text-blueGray-700 mb-2">
                      Jenna Stones
                    </h3>
                    <div className="text-sm leading-normal mt-0 mb-2 text-blueGray-400 font-bold uppercase">
                      <i className="fas fa-map-marker-alt mr-2 text-lg text-blueGray-400"></i>{" "}
                      Los Angeles, California
                    </div>
                    <div className="mb-2 text-blueGray-600 mt-10">
                      <i className="fas fa-briefcase mr-2 text-lg text-blueGray-400"></i>
                      Solution Manager - Creative Tim Officer
                    </div>
                    <div className="mb-2 text-blueGray-600">
                      <i className="fas fa-university mr-2 text-lg text-blueGray-400"></i>
                      University of Computer Science
                    </div>
                  </div>
                  
                  {/* المربع الملون المتحرك (morphing-bg) - نفس اللي في Landing */}
                  <div className="mt-16 mb-10">
                    <div className="flex justify-center items-center">
                      <div className="morphing-bg relative">
                        <div className="image-wrapper">
                          <img 
                            src={profileImageUrl}
                            alt="Profile"
                            className="w-28 h-28 md:w-36 md:h-36 rounded-full object-cover border-4 border-white shadow-xl hover:scale-105 transition-transform duration-300"
                          />
                        </div>
                        <div className="relative z-10 flex flex-col items-center justify-center">
                          <div className="w-full text-white text-center px-4 mt-10">
                            <h2 className="text-2xl md:text-3xl font-bold mb-4 bg-gradient-to-r from-green-400 to-white bg-clip-text text-transparent">
                              Jenna Stones
                            </h2>
                            
                            <div className="mt-4 px-3">
                              <p className="text-base md:text-lg leading-relaxed text-gray-100 max-w-2xl mx-auto">
                                <span className="text-green-400 font-bold">✨</span> 
                                Développeuse passionnée avec une expertise en création d'applications web modernes et innovantes.
                                <span className="text-green-400 font-bold"> ✨</span>
                              </p>
                            </div>
                            
                            <div className="mt-6 flex justify-center gap-3 flex-wrap">
                              <span className="px-3 py-1 text-sm bg-green-500/20 text-green-300 rounded-full border border-green-500/30">
                                🚀 React.js
                              </span>
                              <span className="px-3 py-1 text-sm bg-blue-500/20 text-blue-300 rounded-full border border-blue-500/30">
                                📱 Node.js
                              </span>
                              <span className="px-3 py-1 text-sm bg-purple-500/20 text-purple-300 rounded-full border border-purple-500/30">
                                💡 Tailwind CSS
                              </span>
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                  
                  <div className="mt-10 py-10 border-t border-blueGray-200 text-center">
                    <div className="flex flex-wrap justify-center">
                      <div className="w-full lg:w-9/12 px-4">
                        <p className="mb-4 text-lg leading-relaxed text-blueGray-700">
                          An artist of considerable range, Jenna the name taken by
                          Melbourne-raised, Brooklyn-based Nick Murphy writes,
                          performs and records all of his own music, giving it a
                          warm, intimate feel with a solid groove structure. An
                          artist of considerable range.
                        </p>
                        <a
                          href="#pablo"
                          className="font-normal text-lightBlue-500"
                          onClick={(e) => e.preventDefault()}
                        >
                          Show more
                        </a>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </section>
        </main>
      </div>
      
      <Footer />
    </>
  );
}
